import React, { useState, useEffect, useRef, useCallback } from 'react';

interface LandingPageProps {
  onLoginClick: () => void;
}

type OrbStatus = 'idle' | 'listening' | 'thinking' | 'writing';

const PALETTE = {
  navy:  { r: 30,  g: 42,  b: 74  },
  cream: { r: 245, g: 240, b: 232 },
  tan:   { r: 184, g: 168, b: 152 },
};

const CENNA_LOGO = "data:image/png;base64,";

// ─── Wake-word patterns ───────────────────────────────────────────────────
const WAKE_PATTERNS = [
  'hai cenna', 'hei cenna', 'hey cenna', 'hi cenna',
  'hai senna', 'hei senna', 'hey senna', 'hi senna',
  'hai tenna', 'hei tenna', 'hai cena',  'hey cena',
  'hai xena',  'hai zena',  'hai kena',  'hei kena',
];

function matchesWakeWord(raw: string): boolean {
  const t = raw.toLowerCase().replace(/[^a-z ]/g, '').trim();
  return WAKE_PATTERNS.some((p) => t.includes(p));
}

// ─── Hook: always-on, auto-restarting wake-word listener ─────────────────
function useWakeWord(onDetected: () => void, enabled: boolean) {
  const enabledRef    = useRef(enabled);
  const onDetectedRef = useRef(onDetected);
  const recRef        = useRef<SpeechRecognition | null>(null);
  const timerRef      = useRef<ReturnType<typeof setTimeout> | null>(null);
  const runningRef    = useRef(false);

  useEffect(() => { enabledRef.current = enabled; },     [enabled]);
  useEffect(() => { onDetectedRef.current = onDetected; }, [onDetected]);

  const stop = useCallback(() => {
    runningRef.current = false;
    if (timerRef.current) { clearTimeout(timerRef.current); timerRef.current = null; }
    try { recRef.current?.abort(); } catch { /* ignore */ }
    recRef.current = null;
  }, []);

  const start = useCallback(() => {
    if (!enabledRef.current || runningRef.current) return;
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const SR = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SR) return;

    const rec: SpeechRecognition = new SR();
    rec.lang            = 'id-ID';
    rec.continuous      = true;
    rec.interimResults  = true;
    rec.maxAlternatives = 5;

    rec.onstart = () => { runningRef.current = true; };

    rec.onresult = (evt: SpeechRecognitionEvent) => {
      for (let i = evt.resultIndex; i < evt.results.length; i++) {
        const r = evt.results[i];
        const alts = Array.from({ length: r.length }, (_, j) => r[j].transcript);
        // diagnostic logging — tampilkan teks aktual
        console.log('[Hai Cenna debug]', { final: r.isFinal, alts });
        for (let j = 0; j < r.length; j++) {
          if (matchesWakeWord(r[j].transcript)) {
            onDetectedRef.current();
            return;
          }
        }
      }
    };

    const scheduleRestart = (delay: number) => {
      runningRef.current = false;
      recRef.current     = null;
      if (!enabledRef.current) return;
      timerRef.current = setTimeout(start, delay);
    };

    rec.onend   = () => scheduleRestart(200);
    rec.onerror = (e: SpeechRecognitionErrorEvent) => {
      if (e.error === 'not-allowed' || e.error === 'service-not-allowed') { stop(); return; }
      scheduleRestart(e.error === 'no-speech' ? 100 : 500);
    };

    recRef.current = rec;
    try { rec.start(); } catch { scheduleRestart(500); }
  }, []); // reads refs only — no deps needed

  useEffect(() => {
    if (enabled) { start(); } else { stop(); }
    return stop;
  }, [enabled, start, stop]);
}


// ─── Component ─────────────────────────────────────────────────────────────
export default function LandingPage({ onLoginClick }: LandingPageProps) {
  const [orbState, setOrbState] = useState<OrbStatus>('idle');
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const angleRef  = useRef(0);
  const animIdRef = useRef<number>(0);

  // ── Wake-word: auto-start on mount, request mic permission immediately ──
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const hasSpeechAPI =
    typeof window !== 'undefined' &&
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    !!((window as any).SpeechRecognition || (window as any).webkitSpeechRecognition);

  const [wakeEnabled, setWakeEnabled] = useState(false);
  const [wakeFlash, setWakeFlash]     = useState(false);
  const [lastHeard, setLastHeard]     = useState<string | null>(null);

  // Request mic permission as soon as the page loads and enable wake word
  useEffect(() => {
    if (!hasSpeechAPI) return;
    navigator.mediaDevices.getUserMedia({ audio: true })
      .then(() => setWakeEnabled(true))
      .catch((err) => console.warn('[Hai Cenna] Mic permission denied:', err));
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleWakeWord = useCallback(() => {
    setWakeFlash(true);
    setTimeout(() => setWakeFlash(false), 900);
    setOrbState((prev) => (prev === 'idle' ? 'listening' : prev));
    setLastHeard(new Date().toLocaleTimeString());
    // Navigasi ke login saat wake word terdeteksi
    onLoginClick();
  }, [onLoginClick]);

  useWakeWord(handleWakeWord, wakeEnabled);

  const handleOrbClick = () => {
    setOrbState((prev) =>
      prev === 'idle'      ? 'listening' :
      prev === 'listening' ? 'thinking'  :
      prev === 'thinking'  ? 'writing'   : 'idle'
    );
  };

  // ── Canvas animation ──────────────────────────────────────────────────────
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let w = (canvas.width  = window.innerWidth);
    let h = (canvas.height = window.innerHeight);
    const onResize = () => { w = canvas.width = window.innerWidth; h = canvas.height = window.innerHeight; };
    window.addEventListener('resize', onResize);

    const draw = () => {
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, w, h);
      const cx = w / 2, cy = h / 2;

      let ringAlpha = 0.08, pulseSpeed = 0.012, ringCount = 3, waveAmp = 10;
      let c1 = PALETTE.navy, c2 = PALETTE.tan;

      if      (orbState === 'listening') { c1 = PALETTE.tan;  c2 = PALETTE.navy;  ringAlpha = 0.14; pulseSpeed = 0.028; ringCount = 4; waveAmp = 38; }
      else if (orbState === 'thinking')  { c1 = PALETTE.navy; c2 = PALETTE.cream; ringAlpha = 0.12; pulseSpeed = 0.04;  ringCount = 5; waveAmp = 16; }
      else if (orbState === 'writing')   { c1 = PALETTE.tan;  c2 = PALETTE.cream; ringAlpha = 0.13; pulseSpeed = 0.022; ringCount = 3; waveAmp = 26; }

      angleRef.current += pulseSpeed;
      const a = angleRef.current;

      const aura = ctx.createRadialGradient(cx, cy, 0, cx, cy, 320);
      aura.addColorStop(0,   `rgba(${c1.r},${c1.g},${c1.b},0.07)`);
      aura.addColorStop(0.5, `rgba(${c2.r},${c2.g},${c2.b},0.04)`);
      aura.addColorStop(1,   'rgba(255,255,255,0)');
      ctx.fillStyle = aura;
      ctx.beginPath(); ctx.arc(cx, cy, 320, 0, Math.PI * 2); ctx.fill();

      for (let i = 0; i < ringCount; i++) {
        const t = i / ringCount;
        const r = PALETTE.navy.r * (1 - t) + PALETTE.tan.r * t | 0;
        const g = PALETTE.navy.g * (1 - t) + PALETTE.tan.g * t | 0;
        const b = PALETTE.navy.b * (1 - t) + PALETTE.tan.b * t | 0;
        const radius = (155 + i * 52) * (1 + Math.sin(a + i * 1.4) * 0.1);
        ctx.strokeStyle = `rgba(${r},${g},${b},${ringAlpha - i * 0.012})`;
        ctx.lineWidth   = 1.2 - i * 0.15;
        ctx.beginPath(); ctx.arc(cx, cy, radius, 0, Math.PI * 2); ctx.stroke();
      }

      const drawWave = (
        freq: number, phase: number, amp: number, maxDist: number,
        alpha: number, lw: number, col: { r: number; g: number; b: number }
      ) => {
        ctx.strokeStyle = `rgba(${col.r},${col.g},${col.b},${alpha})`;
        ctx.lineWidth   = lw;
        ctx.beginPath();
        for (let x = 0; x <= w; x += 8) {
          const dist = Math.abs(x - cx);
          const a2   = dist < maxDist ? amp * Math.cos((dist / maxDist) * (Math.PI / 2)) : 0;
          const y    = cy + Math.sin(x * freq + phase) * a2;
          x === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
        }
        ctx.stroke();
      };

      drawWave(0.013,  a * 2.2,        waveAmp,       450, ringAlpha + 0.04, 1.5, c1);
      drawWave(0.018, -a * 1.7 + 1.2,  waveAmp * 0.5, 350, ringAlpha * 0.6,  1.0, c2);

      animIdRef.current = requestAnimationFrame(draw);
    };

    draw();
    return () => { window.removeEventListener('resize', onResize); cancelAnimationFrame(animIdRef.current); };
  }, [orbState]);

  const orbRing = {
    idle:      'ring-[3px] ring-[#1e2a4a]/20',
    listening: 'ring-[5px] ring-[#b8a898]/50',
    thinking:  'ring-[6px] ring-[#1e2a4a]/35',
    writing:   'ring-[4px] ring-[#b8a898]/40',
  }[orbState];

  const glowColor = {
    idle: '#1e2a4a', listening: '#b8a898', thinking: '#1e2a4a', writing: '#b8a898',
  }[orbState];

  return (
    <div className="relative min-h-screen w-full bg-white overflow-hidden flex flex-col items-center justify-center select-none">
      <canvas ref={canvasRef} className="absolute inset-0 z-0 pointer-events-none" />

      {/* Wake-word flash overlay */}
      {wakeFlash && (
        <div className="absolute inset-0 z-20 pointer-events-none"
          style={{ background: 'radial-gradient(circle at center, rgba(184,168,152,0.18) 0%, transparent 70%)',
                   animation: 'wakeFlash 0.9s ease-out forwards' }} />
      )}

      {/* Wordmark top-left */}
      <div className="absolute top-5 left-7 z-30 flex items-center gap-3">
        <img src={CENNA_LOGO} alt="CENNA" className="w-10 h-10 object-contain"
          style={{ filter: 'brightness(0) saturate(100%) invert(14%) sepia(27%) saturate(1200%) hue-rotate(196deg) brightness(95%) contrast(95%)' }} />
        <div className="flex flex-col leading-tight">
          <span className="text-[13px] font-semibold tracking-[0.22em] uppercase"
            style={{ fontFamily: "'DM Sans', sans-serif", color: '#1e2a4a' }}>CENNA AI</span>
          <span className="text-[9px] tracking-[0.18em] uppercase text-[#b8a898]"
            style={{ fontFamily: "'DM Sans', sans-serif" }}>Clinical Intelligence</span>
        </div>
      </div>

      {/* Main content */}
      <div className="relative z-10 flex flex-col items-center justify-center text-center">

        {/* Orb area */}
        <div className="relative flex items-center justify-center" style={{ width: 340, height: 340 }}>

          {/* Green ring — always visible when wake-word is active */}
          {wakeEnabled && (
            <div className="absolute rounded-full pointer-events-none"
              style={{ width: 280, height: 280,
                       border: '1.5px solid rgba(16,185,129,0.35)',
                       animation: 'wakeRingPulse 2.2s ease-in-out infinite' }} />
          )}

          {/* Flash ring on detection */}
          {wakeFlash && (
            <div className="absolute rounded-full pointer-events-none"
              style={{ width: 280, height: 280,
                       border: '2.5px solid rgba(16,185,129,0.7)',
                       animation: 'wakeFlashRing 0.9s ease-out forwards' }} />
          )}

          {/* Outer glow */}
          <div className="absolute rounded-full transition-all duration-700 ease-out"
            style={{ width: 260, height: 260,
                     background: `radial-gradient(circle, ${glowColor}22 0%, transparent 75%)`,
                     filter: 'blur(32px)',
                     transform: `scale(${orbState === 'thinking' ? 1.15 : 1})` }} />

          {/* Main orb */}
          <button id="btn-prime-orb" onClick={handleOrbClick}
            className={`relative rounded-full flex items-center justify-center cursor-pointer border-none transition-all duration-700 ease-out transform hover:-translate-y-1.5 active:scale-95 ${orbRing}`}
            style={{
              width: 200, height: 200,
              background: 'conic-gradient(from 0deg, #1e2a4a 0%, #b8a898 35%, #f5f0e8 55%, #b8a898 75%, #1e2a4a 100%)',
              boxShadow: `0 28px 60px -12px ${glowColor}40, 0 0 0 1px rgba(255,255,255,0.15) inset${wakeFlash ? ', 0 0 0 6px rgba(16,185,129,0.25)' : ''}`,
              animation: 'orbSpin 12s linear infinite',
            }}>
            <div className="absolute rounded-full"
              style={{ inset: 6, background: 'radial-gradient(ellipse at 35% 30%, rgba(255,255,255,0.55) 0%, rgba(255,255,255,0.08) 60%, transparent 100%)' }} />
            <div className="relative flex flex-col items-center justify-center">
              {orbState === 'idle' && (
                <div className="flex gap-[5px] items-end h-7">
                  {[0.5, 0.75, 1, 0.75, 0.5].map((s, i) => (
                    <div key={i} className="w-[3px] rounded-full bg-white/80"
                      style={{ height: `${s * 20}px`, animation: `barBounce 1.4s ease-in-out ${i * 0.12}s infinite alternate`, opacity: 0.7 + s * 0.3 }} />
                  ))}
                </div>
              )}
              {orbState === 'listening' && (
                <div className="flex gap-[5px] items-end h-7">
                  {[0.4, 0.8, 1, 1, 0.8, 0.5, 0.3].map((s, i) => (
                    <div key={i} className="w-[3px] rounded-full bg-white"
                      style={{ height: `${s * 26}px`, animation: `barBounce 0.55s ease-in-out ${i * 0.07}s infinite alternate` }} />
                  ))}
                </div>
              )}
              {orbState === 'thinking' && (
                <div className="relative w-10 h-10 flex items-center justify-center">
                  <div className="absolute w-8 h-8 rounded-full border-2 border-white/60 border-t-transparent"
                    style={{ animation: 'spin 1.5s linear infinite' }} />
                  <div className="w-2 h-2 rounded-full bg-white/90"
                    style={{ animation: 'pulse 1s ease-in-out infinite' }} />
                </div>
              )}
              {orbState === 'writing' && (
                <div className="flex gap-[6px] items-center">
                  {[0, 1, 2].map((i) => (
                    <div key={i} className="w-2 h-2 rounded-full bg-white/80"
                      style={{ animation: `dotPulse 1.2s ease-in-out ${i * 0.2}s infinite` }} />
                  ))}
                </div>
              )}
            </div>
          </button>

          {/* Dashed accent ring */}
          <div className="absolute rounded-full border border-[#1e2a4a]/10 pointer-events-none"
            style={{ width: 236, height: 236, animation: 'spinSlow 18s linear infinite reverse', borderStyle: 'dashed', borderWidth: '1px' }} />
        </div>

        {/* Brand text — NO subtitle */}
        <div className="mt-6 space-y-1">
          <h1 className="text-3xl font-light tracking-[0.22em] uppercase text-[#1e2a4a]"
            style={{ fontFamily: "'DM Sans', sans-serif", letterSpacing: '0.24em' }}></h1>
        </div>

        {/* Wake-word status hint */}
        {lastHeard && (
          <p className="mt-4 text-[9px] tracking-[0.1em] text-emerald-500/70"
            style={{ fontFamily: "'DM Mono', monospace" }}>
            ✓ Terdeteksi pukul {lastHeard}
          </p>
        )}
        {!hasSpeechAPI && (
          <p className="mt-4 text-[9px] tracking-[0.1em] text-[#1e2a4a]/30"
            style={{ fontFamily: "'DM Mono', monospace" }}>
            Wake word tidak didukung browser ini
          </p>
        )}
      </div>

      {/* Bottom status pill */}
      <div className="absolute bottom-8 left-0 right-0 flex justify-center z-10">
        <div className="flex items-center gap-2 px-4 py-1.5 rounded-full border border-[#1e2a4a]/8 bg-white/60 backdrop-blur-sm"
          style={{ fontFamily: "'DM Mono', monospace" }}>
          <span className="w-1.5 h-1.5 rounded-full"
            style={{
              background: orbState === 'idle' ? '#b8a898' : orbState === 'listening' ? '#10b981' : orbState === 'thinking' ? '#1e2a4a' : '#b8a898',
              animation: 'pulse 1.5s ease-in-out infinite',
            }} />
          <span className="text-[10px] tracking-[0.18em] uppercase text-[#1e2a4a]/40 font-medium">
            {orbState === 'idle' ? 'Ready' : orbState === 'listening' ? 'Listening' : orbState === 'thinking' ? 'Analysing' : 'Composing'}
          </span>
        </div>
      </div>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@300;400;500;600;700&family=DM+Mono:wght@400;500&display=swap');
        @keyframes orbSpin    { from{filter:hue-rotate(0deg) brightness(1.02)} 50%{filter:hue-rotate(8deg) brightness(1.06)} to{filter:hue-rotate(0deg) brightness(1.02)} }
        @keyframes barBounce  { from{transform:scaleY(0.5);opacity:0.5} to{transform:scaleY(1);opacity:1} }
        @keyframes dotPulse   { 0%,100%{transform:scale(0.7);opacity:0.4} 50%{transform:scale(1.2);opacity:1} }
        @keyframes spinSlow   { from{transform:rotate(0deg)} to{transform:rotate(360deg)} }
        @keyframes spin       { from{transform:rotate(0deg)} to{transform:rotate(360deg)} }
        @keyframes pulse      { 0%,100%{opacity:0.5;transform:scale(0.9)} 50%{opacity:1;transform:scale(1.1)} }
        @keyframes wakeRingPulse { 0%{transform:scale(1);opacity:0.5} 50%{transform:scale(1.06);opacity:0.25} 100%{transform:scale(1);opacity:0.5} }
        @keyframes wakeFlashRing { 0%{transform:scale(1);opacity:1} 100%{transform:scale(1.18);opacity:0} }
        @keyframes wakeFlash     { 0%{opacity:1} 100%{opacity:0} }
      `}</style>
    </div>
  );
}
